import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const countryCodes = [
  { code: "+1", name: "United States" },
  { code: "+44", name: "United Kingdom" },
  { code: "+91", name: "India" },
  { code: "+61", name: "Australia" },
  { code: "+81", name: "Japan" },
  { code: "+49", name: "Germany" },
  { code: "+33", name: "France" },
  { code: "+86", name: "China" },
  { code: "+7", name: "Russia" },
  { code: "+55", name: "Brazil" },
  // Add more countries as needed
];

export default function Register({ onRegister }) {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    otp: "",
  });
  const [selectedCountryCode, setSelectedCountryCode] = useState("+91");
  const [otpSent, setOtpSent] = useState(false);
  const [otpVerified, setOtpVerified] = useState(false);
  const [emailValid, setEmailValid] = useState(false);
  const [phoneValid, setPhoneValid] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  // Added missing onShowLogin handler to fix ESLint error
  const onShowLogin = () => {
    navigate('/login');
  };

  const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000";

  useEffect(() => {
    // Basic email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    setEmailValid(emailRegex.test(form.email));
    // Basic phone validation (digits only, length exactly 10)
    const phoneRegex = /^\d{10}$/;
    setPhoneValid(phoneRegex.test(form.phone));
  }, [form.email, form.phone]);

  const handleChange = (e) => {
    // Prevent entering '+' or non-digit characters in phone input
    if (e.target.name === "phone") {
      const value = e.target.value;
      if (/^\d*$/.test(value)) {
        setForm({ ...form, [e.target.name]: value });
      }
    } else {
      setForm({ ...form, [e.target.name]: e.target.value });
    }
  };

  const handleCountryCodeChange = (e) => {
    setSelectedCountryCode(e.target.value);
  };

  const sendOtp = async () => {
    if (!phoneValid) {
      setError("Please enter a valid phone number");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      const res = await fetch(API_BASE + "/api/auth/send-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: fullPhone, isRegistration: true }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setOtpSent(true);
      } else {
        setError(data.message || "Failed to send OTP");
      }
    } catch (e) {
      setError("Network error");
    }
    setLoading(false);
  };

  const verifyOtp = async () => {
    if (!form.otp) {
      setError("Please enter the OTP");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      const res = await fetch(API_BASE + "/api/auth/verify-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: fullPhone, otp: form.otp, isRegistration: true }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setOtpVerified(true);
      } else {
        setError(data.message || "OTP verification failed");
      }
    } catch (e) {
      setError("Network error");
    }
    setLoading(false);
  };

  const handleSubmit = async () => {
    if (!otpVerified || !emailValid || !phoneValid) {
      setError("Please complete all validations");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      // Remove username from the data sent to backend
      const { name, email, address, otp } = form;
      const res = await fetch(API_BASE + "/api/auth/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, phone: fullPhone, email, address, otp }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        onRegister(data.user);
      } else {
        setError(data.message || "Registration failed");
      }
    } catch (e) {
      setError("Network error");
    }
    setLoading(false);
  };

  return (
    <div className="register-container" style={{ maxWidth: 400, margin: "auto", padding: 20, backgroundColor: "#1e1e2f", borderRadius: 12, color: "#fff" }}>
      <h2 style={{ marginBottom: 20 }}>Create Account</h2>

      <input
        name="name"
        placeholder="Full Name"
        value={form.name}
        onChange={handleChange}
        style={{ width: "100%", padding: 12, marginBottom: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
      />
      <div style={{ display: "flex", marginBottom: 12 }}>
        <select
          value={selectedCountryCode}
          onChange={handleCountryCodeChange}
          style={{ padding: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16, marginRight: 8, flexShrink: 0 }}
        >
          {countryCodes.map((country) => (
            <option key={country.code} value={country.code}>
              {country.name} ({country.code})
            </option>
          ))}
        </select>
        <input
          name="phone"
          placeholder="Phone Number"
          value={form.phone}
          onChange={handleChange}
          style={{ flexGrow: 1, padding: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
        />
      </div>
      <button onClick={sendOtp} disabled={!phoneValid || otpSent} style={{ marginBottom: 12, padding: 10, borderRadius: 8, backgroundColor: "#00f0ff", color: "#000", fontWeight: "bold", cursor: "pointer" }}>
        {otpSent ? "OTP Sent" : "Send OTP"}
      </button>

      {otpSent && !otpVerified && (
        <>
          <input
            name="otp"
            placeholder="Enter OTP"
            value={form.otp}
            onChange={handleChange}
            style={{ width: "100%", padding: 12, marginBottom: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
          />
          <button onClick={verifyOtp} disabled={loading} style={{ marginBottom: 12, padding: 10, borderRadius: 8, backgroundColor: "#00f0ff", color: "#000", fontWeight: "bold", cursor: "pointer" }}>
            Verify OTP
          </button>
        </>
      )}

      <input
        name="email"
        placeholder="Email"
        value={form.email}
        onChange={handleChange}
        style={{ width: "100%", padding: 12, marginBottom: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
      />
      <input
        name="address"
        placeholder="Address"
        value={form.address}
        onChange={handleChange}
        style={{ width: "100%", padding: 12, marginBottom: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
      />

      <button
        onClick={handleSubmit}
        disabled={!otpVerified || !emailValid || !phoneValid || loading}
        style={{ width: "100%", padding: 12, backgroundColor: "#00f0ff", border: "none", borderRadius: 8, color: "#000", fontWeight: "bold", cursor: "pointer" }}
      >
        {loading ? "Submitting..." : "Sign Up"}
      </button>

      <div style={{ marginTop: 12 }}>
        <button onClick={onShowLogin} style={{ background: "none", border: "none", color: "#00f0ff", cursor: "pointer", textDecoration: "underline" }}>
          Already have an account? Login here
        </button>
      </div>

      {error && <div style={{ marginTop: 12, color: "#ff4d4f" }}>{error}</div>}
    </div>
  );
}
